// /frontend/src/components/WeatherApp.jsx
import React, { useEffect, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

const API_BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

const ATL = { name: "Atlanta,US", lat: 33.7490, lon: -84.3880 };
const isFiniteNum = (n) => typeof n === "number" && isFinite(n);

// ---- Normalize ANY backend shape into { current, hourly[], daily[], summary } ----
function normalizePayload(p) {
  if (!p || typeof p !== "object") return { current: null, hourly: [], daily: [], summary: "" };

  // unwrap if payload.weather exists (your sample shows this)
  const root = p.weather && typeof p.weather === "object" ? p.weather : p;

  // current
  const cur = root.current || {};
  const current = {
    temp: cur.temp ?? cur.temperature ?? null,
    weather: cur.weather ?? cur.description ?? "",
    precipitation: cur.precipitation ?? cur.rain ?? cur.snow ?? 0,
    dt: cur.dt ?? Math.floor(Date.now() / 1000),
  };

  // hourly
  const hourlySrc = Array.isArray(root.hourly) ? root.hourly : [];
  const hourly = hourlySrc.map((h, i) => ({
    dt: h.dt ?? h.date ?? Math.floor(Date.now() / 1000) + (i + 1) * 3600,
    temp: h.temp ?? h.temperature ?? null,
    pop: typeof h.pop === "number" ? Math.max(0, Math.min(1, h.pop)) : 0,
    precipitation: h.precipitation ?? h.rain ?? h.snow ?? 0,
    weather: h.weather ?? h.description ?? "",
  }));

  // daily
  const dailySrc = Array.isArray(root.daily) ? root.daily : [];
  const daily = dailySrc.map((d, i) => {
    const t = d.temp || {};
    return {
      dt: d.dt ?? d.date ?? Math.floor(Date.now() / 1000) + (i + 1) * 86400,
      min: t.min ?? d.min ?? null,
      max: t.max ?? d.max ?? null,
      pop: typeof d.pop === "number" ? Math.max(0, Math.min(1, d.pop)) : 0,
      precipitation: d.precipitation ?? d.rain ?? d.snow ?? 0,
      weather: d.weather ?? d.description ?? "",
    };
  });

  return {
    current: current.temp != null ? current : null,
    hourly,
    daily,
    summary: p.summary ?? "",
    _raw: p, // for debug if needed
  };
}

export default function WeatherApp() {
  const [place, setPlace] = useState(ATL);
  const [view, setView] = useState("now"); // "now" | "chatbot" | "community"

  const [weather, setWeather] = useState({
    current: null,
    hourly: [],
    daily: [],
    summary: "",
  });
  const [daily16, setDaily16] = useState([]);
  const [wLoading, setWLoading] = useState(false);
  const [wError, setWError] = useState("");
  const [debugRaw, setDebugRaw] = useState(null);

  function handleSearchSelect(p) {
    if (typeof p === "string") {
      setPlace({ name: p.trim() || ATL.name, lat: ATL.lat, lon: ATL.lon });
      return;
    }
    setPlace({
      name: p?.name || ATL.name,
      lat: isFiniteNum(p?.lat) ? p.lat : ATL.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : ATL.lon,
    });
  }

  useEffect(() => {
    let abort = false;

    async function run() {
      try {
        setWLoading(true);
        setWError("");

        // Single call: /api/weather/current
        const r = await fetch(`${API_BASE}/api/weather/current`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            location: place.name,
            lat: place.lat,
            lon: place.lon,
          }),
        });

        if (!r.ok) {
          const t = await r.text().catch(() => "");
          throw new Error(`current failed: HTTP ${r.status} ${t}`);
        }

        const payload = await r.json();
        if (abort) return;

        const norm = normalizePayload(payload);
        setWeather({
          current: norm.current,
          hourly: norm.hourly,
          daily: norm.daily,
          summary: norm.summary,
        });

        // derive 16‑day from same response (slice if we have it)
        setDaily16(norm.daily.slice(0, 16));
        setDebugRaw(norm._raw || payload); // optional debugging pane
      } catch (e) {
        if (!abort) {
          console.error(e);
          setWError(e.message || "Failed to load weather");
          setWeather({ current: null, hourly: [], daily: [], summary: "" });
          setDaily16([]);
          setDebugRaw(null);
        }
      } finally {
        if (!abort) setWLoading(false);
      }
    }

    if (place?.name) run();
    return () => { abort = true; };
  }, [place.name, place.lat, place.lon]);

  const now = weather.current || {};

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      <WeatherOverlay condition={now?.weather} />

      {/* Search */}
      <header className="px-4 pt-4">
        <div className="mx-auto w-full max-w-5xl">
          <SearchSection defaultValue={place?.name || ""} onSelect={handleSearchSelect} />
        </div>
      </header>

      {/* Status */}
      {wLoading && <div className="px-4 mt-2 text-xs text-gray-600">Loading weather…</div>}
      {!wLoading && wError && <div className="px-4 mt-2 text-xs text-red-600">{wError}</div>}

      {/* Header card */}
      <section className="px-4 mt-3">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
            <div className="text-sm opacity-90">Now in</div>
            <div className="text-xl font-semibold">{place?.name}</div>
            <div className="text-5xl font-bold mt-1">
              {now?.temp != null ? Math.round(now.temp) : "--"}°C
            </div>
            <div className="opacity-80">{now?.weather || (weather.summary ? "" : "—")}</div>
            {weather.summary && <div className="mt-3 opacity-90">{weather.summary}</div>}
          </div>
        </div>
      </section>

      {/* Views */}
      <main className="px-4 mt-6 pb-28">
        <div className="mx-auto w-full max-w-5xl">
          {view === "now" && (
            <>
              <section className="mb-6">
                <Radar
                  center={[
                    isFiniteNum(place?.lat) ? place.lat : ATL.lat,
                    isFiniteNum(place?.lon) ? place.lon : ATL.lon,
                  ]}
                  zoom={6}
                  height={320}
                  className="rounded-2xl overflow-hidden"
                />
              </section>
              <section>
                <Forecast hourly={weather.hourly} daily={weather.daily} daily16={daily16} />
              </section>
            </>
          )}

          {view === "chatbot" && (
            <ChatBox location={place?.name || ATL.name} />
          )}

          {view === "community" && (
            <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
              <div className="font-semibold mb-2">Community</div>
              <div className="text-sm opacity-80">
                This demo view requires JWT auth to list/post. Add a login UI to call
                <code className="mx-1 px-1 rounded bg-white/10">/api/auth/token</code> and then hit
                <code className="mx-1 px-1 rounded bg-white/10">/api/community/posts</code> with the token.
              </div>
            </div>
          )}

          {/* OPTIONAL: quick debug view while wiring */}
          {!wLoading && !wError && !weather.current && (
            <pre className="mt-4 p-3 text-xs bg-black/5 rounded">
              No “current” parsed. Raw payload (truncated):
              {JSON.stringify(debugRaw, null, 2).slice(0, 1200)}…
            </pre>
          )}
        </div>
      </main>

      <BottomBar active={view} onNav={setView} />
    </div>
  );
}

/** Tiny chat component that calls /api/weather/chat */
function ChatBox({ location }) {
  const [q, setQ] = useState("");
  const [a, setA] = useState("");
  const [loading, setLoading] = useState(false);

  async function ask(e) {
    e.preventDefault();
    if (!q.trim()) return;
    setLoading(true);
    setA("");
    try {
      const res = await fetch(`${API_BASE}/api/weather/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ location, question: q }),
      });
      if (!res.ok) throw new Error(`Chat failed: HTTP ${res.status}`);
      const data = await res.json();
      setA(data?.response || "");
    } catch (err) {
      setA(err.message || "Chat failed.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
      <div className="font-semibold mb-2">Ask about the forecast</div>
      <form onSubmit={ask} className="flex gap-2">
        <input
          value={q}
          onChange={(e) => setQ(e.target.value)}
          placeholder={`Ask about ${location}…`}
          className="flex-1 px-3 py-2 rounded-lg bg-white/10 outline-none"
        />
        <button className="px-3 py-2 rounded-lg bg-purple-600 text-white" disabled={loading}>
          {loading ? "Asking…" : "Ask"}
        </button>
      </form>
      {a && <div className="mt-3 text-sm whitespace-pre-wrap">{a}</div>}
    </div>
  );
}
